(1, 74, 'shuvo', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n  <meta charset=\"UTF-8\" />\r\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n  <title>Buy Now - Mobile Shop</title>\r\n  <script src=\"https://cdn.tailwindcss.com\"></script>\r\n</head>\r\n<body class=\"bg-gray-100 text-gray-800\">\r\n\r\n  <div class=\"max-w-3xl mx-auto bg-white shadow-md mt-10 p-6 rounded-lg\">\r\n    <!-- Product Info -->\r\n    <div class=\"grid md:grid-cols-2 gap-6\">\r\n      <div>\r\n        <img src=\"https://via.placeholder.com/400x400?text=Mobile+Image\" alt=\"Mobile Product\" class=\"w-full rounded-lg shadow\">\r\n      </div>\r\n      <div>\r\n        <h2 class=\"text-2xl font-bold mb-2\">Samsung Galaxy S24 Ultra</h2>\r\n        <p class=\"text-gray-600 mb-4\">Experience next-level mobile performance with the powerful Samsung Galaxy S24 Ultra – stunning display, fast processor, and incredible camera.</p>\r\n        \r\n        <div class=\"mb-4\">\r\n          <span class=\"text-3xl font-semibold text-green-600\">$1,099.00</span>\r\n        </div>\r\n\r\n        <form action=\"/buy-now\" method=\"POST\">\r\n          <!-- Quantity -->\r\n          <div class=\"mb-4\">\r\n            <label for=\"quantity\" class=\"block text-sm font-medium mb-1\">Quantity</label>\r\n            <input type=\"number\" id=\"quantity\" name=\"quantity\" value=\"1\" min=\"1\" class=\"w-24 px-3 py-2 border rounded-md focus:outline-none focus:ring focus:ring-blue-300\">\r\n          </div>\r\n\r\n          <!-- Color (optional) -->\r\n          <div class=\"mb-4\">\r\n            <label class=\"block text-sm font-medium mb-1\">Color</label>\r\n            <select name=\"color\" class=\"w-full px-3 py-2 border rounded-md\">\r\n              <option>Phantom Black</option>\r\n              <option>Green</option>\r\n              <option>Graphite</option>\r\n            </select>\r\n          </div>\r\n\r\n          <!-- Buy Now Button -->\r\n          <button type=\"submit\" class=\"w-full bg-blue-600 text-white py-3 rounded-md font-semibold hover:bg-blue-700 transition\">\r\n            Buy Now\r\n          </button>\r\n        </form>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- Additional Info -->\r\n    <div class=\"mt-8\">\r\n      <h3 class=\"text-xl font-semibold mb-2\">Product Highlights</h3>\r\n      <ul class=\"list-disc list-inside text-sm text-gray-700\">\r\n        <li>6.8\" Dynamic AMOLED Display</li>\r\n        <li>Snapdragon 8 Gen 3 Processor</li>\r\n        <li>200MP + 12MP + 10MP Cameras</li>\r\n        <li>5000mAh Battery</li>\r\n        <li>One UI 6, Android 14</li>\r\n      </ul>\r\n    </div>\r\n  </div>\r\n\r\n</body>\r\n</html>', 1, '0000-00-00 00:00:00', '2025-07-15 11:32:01');
